then.script:
// -----------------------------------
// Date Formatting
// -----------------------------------
function formatNow(dateObj) {
    return dateObj.toLocaleString("en-US", {
        month: "long",
        day: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        hour12: true
    });
}

var nowFormatted = formatNow(new Date());

// -----------------------------------
// Subject
// -----------------------------------
var subject = "REFUND SUCCESSFUL";
mc.setProperty("Email_Subject", subject);

// -----------------------------------
// HTML Body
// -----------------------------------
var emailBody =
    '<!doctype html>' +
    '<html lang="en">' +
    '<head>' +
    '  <meta charset="utf-8">' +
    '  <meta name="viewport" content="width=device-width, initial-scale=1.0" />' +
    '  <style>' +
    '    body { margin:0; padding:0; font-family:Arial, Helvetica, sans-serif; background:#f4f6f8; color:#333; }' +
    '    .container { max-width:700px; margin:20px auto; background:#fff; border-radius:6px; box-shadow:0 2px 6px rgba(0,0,0,0.15); }' +
    '    .header { background:#ADFF2F; padding:24px; text-align:center; color:#fff; font-size:26px; font-weight:bold; }' +
    '    .subheader { text-align:center; padding:10px 0; font-size:14px; color:#ffe6e6; }' +
    '    .body { padding:30px; font-size:15px; line-height:1.6; }' +
    '    .section-title { font-size:20px; font-weight:bold; margin-bottom:20px; text-align:center; }' +
    '    .info-box { background:#fff2f2; border-left:5px solid #d00000; padding:15px; margin:20px 0; border-radius:4px; }' +
    '    .footer { padding:20px; text-align:center; font-size:12px; color:#9aa7bf; }' +
    '  </style>' +
    '</head>' +
    '<body>' +
    '  <div class="container">' +
    '    <div class="header">Your Refund Has Been Processed Successfully</div>' +
    '    <div class="body">' +
    '      <p>' + nowFormatted + '</p>' +
    '      <p>Dear User,</p>' +
    '      <p>This is to inform you that your refund request related to your policy has been successfully processed. The refund amount has been initiated and will be credited to your original mode of payment shortly.</p>' +
    '      <p>Please note that it may take a few business days for the amount to reflect in your account, depending on your bank or payment provider.</p>' +
    '      <p>If you have any questions or need further assistance, feel free to reach out to our support team. Thank you for choosing us.</p>' +
    '      <p>Sincerely,<br><br>' +
    '      <strong>Exasure IIC</strong><br>' +
    '      Policy &amp; Customer Support</p>' +
    '    </div>' +
    '    <div class="footer">' +
    '      Exasure IIC | http://localhost:5173/home<br>' +
    '      This is an automated message. Please do not reply.' +
    '    </div>' +
    '  </div>' +
    '</body>' +
    '</html>';

mc.setProperty("Email_Body", emailBody);
